import React, { useState, useEffect } from 'react';
import { useTable } from 'react-table';

const columns = [
  { Header: 'ID', accessor: 'id' },
  { Header: 'Location', accessor: 'locationname' },
  { Header: 'Material ID', accessor: 'materialid' },
  { Header: 'Material Name', accessor: 'name' },
  { Header: 'Quantity', accessor: 'quantity' },
  { Header: 'Date', accessor: 'date' },
];

function PurchaseFunc() {
  const [purchases, setPurchases] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setIsLoading(true);
    setError(null);

    try {
      const response = await fetch('http://localhost:8081/PurchasesAPI');
      if (!response.ok) {
        throw new Error('Failed to fetch data');
      }
      const data = await response.json();

      const locationIds = data.map(item => item.location);
      const materialIds = data.map(item => item.materialId);

      const [locationResponse, materialResponse] = await Promise.all([
        fetch(`http://localhost:8081/LocationsAPI?ids=${locationIds.join(',')}`),
        fetch(`http://localhost:8081/materiallist?ids=${materialIds.join(',')}`),
      ]);

      if (!locationResponse.ok || !materialResponse.ok) {
        throw new Error('Failed to fetch additional data');
      }

      const locationData = await locationResponse.json();
      const materialData = await materialResponse.json();

      const locationMap = locationData.reduce((map, location) => {
        map[location.id] = location.name;
        return map;
      }, {});

      const materialMap = materialData.reduce((map, material) => {
        map[material.id] = material.name;
        return map;
      }, {});

      const updatedData = data.map(item => ({
        ...item,
        locationName: locationMap[item.location] || '', // Use locationMap to get location name
        materialName: materialMap[item.materialId] || '', // Use materialMap to get material name
      }));

      setPurchases(updatedData);
    } catch (error) {
      setError(error);
    } finally {
      setIsLoading(false);
    }
  };

  const tableInstance = useTable({ columns, data: purchases });

  const { getTableProps, getTableBodyProps, headerGroups, rows, prepareRow } = tableInstance;

  return (
    <div>
      <h1>My Purchases</h1>
      {isLoading ? (
        <div>Loading...</div>
      ) : error ? (
        <div>Error: {error.message}</div>
      ) : (
        <table {...getTableProps()} style={{ border: '1px solid black' }}>
          <thead>
            {headerGroups.map(headerGroup => (
              <tr {...headerGroup.getHeaderGroupProps()} style={{ background: 'lightgray' }}>
                {headerGroup.headers.map(column => (
                  <th
                    {...column.getHeaderProps()}
                    style={{ padding: '5px', border: '1px solid black' }}
                  >
                    {column.render('Header')}
                  </th>
                ))}
              </tr>
            ))}
          </thead>
          <tbody {...getTableBodyProps()}>
            {rows.map(row => {
              prepareRow(row);
              return (
                <tr {...row.getRowProps()}>
                  {row.cells.map(cell => (
                    <td
                      {...cell.getCellProps()}
                      style={{ padding: '5px', border: '1px solid black' }}
                    >
                      {cell.render('Cell')}
                    </td>
                  ))}
                </tr>
              );
            })}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default PurchaseFunc;
